class MKAverage {
public:
    int m, k;
    deque<int> dq;
    MKAverage(int m, int k) : m(m), k(k) {}

    void addElement(int num) {
        dq.push_back(num);
        if (dq.size() > m) dq.pop_front();
    }

    int calculateMKAverage() {
        if (dq.size() < m) return -1;
        vector<int> v(dq.begin(), dq.end());
        sort(v.begin(), v.end());
        int sum = 0;
        for (int i = k; i < m - k; i++) sum += v[i];
        return sum / (m - 2 * k);
    }
};

